# GraphQL schema with query depth limiting via middleware
class DepthAnalysisMiddleware:
    """Middleware to prevent deeply nested queries (DoS protection)."""

    def resolve(self, next, root, info, **args):
        # Check query depth
        depth = self._get_depth(info.field_nodes[0])
        if depth > MAX_QUERY_DEPTH:
            raise graphene.GraphQLError(
                f"Query depth {depth} exceeds maximum allowed depth of {MAX_QUERY_DEPTH}"
            )
        return next(root, info, **args)

    def _get_depth(self, node, current_depth=1):
        if not hasattr(node, "selection_set") or node.selection_set is None:
            return current_depth
        max_depth = current_depth
        for selection in node.selection_set.selections:
            child_depth = self._get_depth(selection, current_depth + 1)
            if child_depth > max_depth:
                max_depth = child_depth
        return max_depth


